def transition(read, write, move)
      if read == @memory[@head]
        @memory[@head] = write
        case move
        when 'R'
          @memory << '@' if @memory[@head + 1]
          @head += 1
        when 'L'
          @memory.unshift('@') if @head == 0
          @head -= 1
        end
        return true
      else
        return false
      end
    end

